import test from "node:test";
import assert from "node:assert/strict";
import { createRateLimiter } from "../src/rate_limit.js";

test("allows up to limit then blocks", () => {
  const rl = createRateLimiter({ limit: 2, windowMs: 60_000 });
  assert.equal(rl.allow("a"), true);
  assert.equal(rl.allow("a"), true);
  assert.equal(rl.allow("a"), false);
  assert.equal(rl.remaining("a"), 0);
});

test("keys are independent", () => {
  const rl = createRateLimiter({ limit: 1, windowMs: 60_000 });
  assert.equal(rl.allow("a"), true);
  assert.equal(rl.allow("b"), true);
});

test("reset restores tokens", () => {
  const rl = createRateLimiter({ limit: 1, windowMs: 60_000 });
  assert.equal(rl.allow("a"), true);
  assert.equal(rl.allow("a"), false);
  rl.reset("a");
  assert.equal(rl.allow("a"), true);
});
